 {"id":"bd-10y0","title":"QUIC endpoint: quinn wrapper with Cx integration","description":"# QUIC Endpoint Implementation

## Overview
Wrap the quinn QUIC library with Cx integration, providing cancel-correct
QUIC endpoint and connection management.

## Design

### QuicConfig
```rust
pub struct QuicConfig {
    /// Certificate chain for server.
    pub cert_chain: Option<Vec<Certificate>>,
    /// Private key for server.
    pub private_key: Option<PrivateKey>,
    /// Client authentication requirement.
    pub client_auth: ClientAuth,
    /// Maximum concurrent bidirectional streams.
    pub max_bi_streams: u32,
    /// Maximum concurrent unidirectional streams.
    pub max_uni_streams: u32,
    /// Keep-alive interval.
    pub keep_alive: Option<Duration>,
}
```

### QuicEndpoint
```rust
pub struct QuicEndpoint {
    inner: quinn::Endpoint,
    runtime_handle: RuntimeHandle,
}

impl QuicEndpoint {
    /// Create client endpoint.
    pub fn client(cx: &Cx, config: QuicConfig) -> Outcome<Self, QuicError> {
        cx.checkpoint()?;
        let crypto = rustls::ClientConfig::builder()
            .with_safe_defaults()
            .with_root_certificates(/* roots */)
            .with_no_client_auth();

        let client_config = quinn::ClientConfig::new(Arc::new(crypto));
        let endpoint = quinn::Endpoint::client(/* bind addr */)?;
        endpoint.set_default_client_config(client_config);

        Ok(Self { inner: endpoint, /* ... */ })
    }

    /// Create server endpoint.
    pub fn server(
        cx: &Cx,
        addr: SocketAddr,
        config: QuicConfig,
    ) -> Outcome<Self, QuicError>;

    /// Connect to remote server.
    pub async fn connect(
        &self,
        cx: &Cx,
        addr: SocketAddr,
        server_name: &str,
    ) -> Outcome<QuicConnection, QuicError> {
        cx.checkpoint()?;

        let connecting = self.inner.connect(addr, server_name)?;

        // Wait for connection with Cx cancellation
        match cx.race(connecting).await {
            Outcome::Ok(conn) => Ok(QuicConnection::new(conn)),
            Outcome::Cancelled => {
                // Quinn handles cleanup
                Err(QuicError::Cancelled)
            }
            Outcome::Err(e) => Err(e.into()),
        }
    }

    /// Accept incoming connection.
    pub async fn accept(&self, cx: &Cx) -> Outcome<QuicConnection, QuicError> {
        cx.checkpoint()?;

        let incoming = self.inner.accept().await
            .ok_or(QuicError::EndpointClosed)?;

        let conn = incoming.await?;
        Ok(QuicConnection::new(conn))
    }
}
```

