    assert!(matches!(result, Err(H2Error::Protocol(_))));

    // PUSH_PROMISE on server-initiated stream (wrong direction)
    let result = client.receive_push_promise(/*even*/ 2, 4, &[]);
    assert!(matches!(result, Err(H2Error::Protocol(_))));
}
