        let s2 = Arc::clone(&streams);
        let t2 = thread::spawn(move || {
            let map = s2.lock().unwrap();
            map.can_reserve_more()
        });

        t1.join().unwrap();
        t2.join().unwrap();

        let map = streams.lock().unwrap();
        assert!(map.reserved_count() <= 1);
    });
}

#[test]
fn loom_push_promise_vs_rst_stream_race() {
    loom::model(|| {
        let conn = Arc::new(Mutex::new(ConnectionState::new()));

        // Thread 1: PUSH_PROMISE arrives
        let c1 = Arc::clone(&conn);
        let t1 = thread::spawn(move || {
            let mut state = c1.lock().unwrap();
            state.receive_push_promise(2)
        });

        // Thread 2: RST_STREAM for promised stream
        let c2 = Arc::clone(&conn);
        let t2 = thread::spawn(move || {
            let mut state = c2.lock().unwrap();
            state.receive_rst_stream(2)
        });

        t1.join().unwrap();
        t2.join().unwrap();

        // Stream should be in valid terminal state
        let state = conn.lock().unwrap();
        let stream = state.get_stream(2);
        assert!(stream.is_none() || stream.unwrap().is_closed());
    });
}
