### Tree Rendering (raid from rich_rust/tree.rs)
```rust
pub struct RegionTree {
    console: Console,
    state: Arc<RuntimeState>,
}

impl RegionTree {
    /// Render the current region tree.
    pub fn render(&self) -> String {
        let root = self.state.root_region();
        self.render_region(&root, 0, true)
    }

    fn render_region(&self, region: &Region, depth: usize, is_last: bool) -> String {
        let prefix = self.tree_prefix(depth, is_last);
        let status = self.region_status(region);
        let budget = self.budget_bar(region);

        format!(
            "{}{} {} [{}] {}",
            prefix,
            self.region_icon(region),
            region.id(),
            status,
            budget
        )
    }
}
```

